import React from 'react';
import { Card, CardContent, Typography, Box, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface CurrentRide {
  estimatedFare: number;
  arrivalTime: string;
  driver: {
    name: string;
    rating: number;
  };
}

interface PreviousRide {
  date: string;
  fare: number;
}

interface RideShareData {
  currentRide: CurrentRide;
  previousRides: PreviousRide[];
}

export default function Widget() {
  const { currentRide, previousRides } = response.data as RideShareData;
  const isFareIncreased = previousRides.length > 0 && currentRide.estimatedFare > previousRides[0].fare;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Current Ride
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              ${currentRide.estimatedFare.toFixed(2)}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isFareIncreased ? <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />}
              <Typography variant="body2" sx={{ color: isFareIncreased ? '#10B981' : '#EF4444' }}>
                {currentRide.arrivalTime} to arrival
              </Typography>
            </Stack>
          </Box>

          <Stack direction="row" spacing={1.5} alignItems="center">
            <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
              Driver: {currentRide.driver.name}
            </Typography>
            <Chip label={`Rating: ${currentRide.driver.rating}`} sx={{ fontSize: '11px', bgcolor: '#FFC107', color: '#000' }} />
          </Stack>

          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Previous Rides
            </Typography>
            <Stack spacing={0.5}>
              {previousRides.slice(0, 3).map((ride, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ color: '#F8FAFC' }}>
                    {ride.date}: ${ride.fare.toFixed(2)}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
